THE CLAIM:
{
 "title": "One vendor's colo definition inflates the European market base",
 "narrative": "The model builds every geography and the 39.8% Central-Europe share of tamBase from a single Statista series. But adding up Statista's 2024 country figures gives about 7.6GW, more than CBRE's 5.8GW for all of Europe. If that series counts capacity that isn't really there, tamBase is sized too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Statista's country colo figures use an unverified, unmatched scope",
   "refs": [
    "digest:geo-region-denominator#c1",
    "digest:geo-region-denominator#c3",
    "digest:geo-region-denominator#c5"
   ]
  },
  {
   "step": "propagation",
   "text": "PMR data shows the region roughly five times smaller",
   "refs": [
    "digest:geo-PL#c13",
    "digest:geo-PL#c14",
    "ledger:geo.PL"
   ]
  },
  {
   "step": "model-impact",
   "text": "Fixing the scope shrinks the Central-Europe slice and tamBase",
   "refs": [
    "ledger:tamBase",
    "ledger:geo.DE",
    "digest:geo-region-denominator#c5"
   ]
  }
 ],
 "falsifier": "A second vendor such as DC Byte or CBRE reproducing Statista's per-country 2025 colocation MW within about 15% under an identical definition.",
 "category": "fact",
 "evidence": [
  {
   "title": "Colocation data center investment Europe 2031 (methodology note defining scale colocation)",
   "sourceType": "industry-report",
   "publisher": "Statista",
   "date": "2026-02-06",
   "excerpt": "The source defines scale colocation data centers as \"very large facilities that are built-to-scale and/or powered shells by colocation data center operators; typically, 20 MW.\"",
   "url": "https://www.statista.com/statistics/1659983/colocation-data-center-investment-europe/",
   "attached": true
  },
  {
   "title": "Europe Data Centres Figures Q4 2024",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025-02",
   "excerpt": "4,726MW European colocation supply 470MW European colocation availability 341MW European colocation take-up",
   "url": "https://assoimmobiliare-be.afterpixel.com/app/uploads/2025/02/Europe-Data-Centres-Figures-Q4-2024.pdf",
   "attached": true
  },
  {
   "title": "European Data Centres Overview",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2024-07-22",
   "excerpt": "5.8GW Data centre capacity expected across Europe by the end of 2024",
   "url": "https://www.cbre.com/insights/reports/european-data-centres-overview",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 320,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 520
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €320M",
   "crossCheck": "Europe DC PDUs+PSUs $2.45B 2024 (BIS/R&M, broader scope) × ~55% PDU share × 39.8% CE ≈ €495M — sets the high end of the band"
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; both sizing chains are scope-downs from adjacent scopes → wide band, top value-of-information.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
